#La logique pour le founisseur
def add_fourniseur(nom,adresse,telephone,email,tab):
    res=Messagebox.yesnocancel(title="Question",message=f"Voulez vous ajouter le fournisseur qui s'appelle {nom} ?")
    if res=="Yes":
            fournisseur_db = root_fourisseur.xpath(f"//fournisseur[nom_fournisseur='{nom}']")
            #on test si le founisseur existe deja
            if len(fournisseur_db)>0:
                Messagebox.show_warning(title="Antention",message=f"le fournisseur qui s'appelle {nom} existe déja!",parent=root)
            else:#sinon
                id= nombre_ID_BD(root_fourisseur, '//fournisseur')
                id+= 1  # on ajoute un a l'i
                new_founisseur=etree.Element("fournisseur",id_fournisseur=str(id))
                etree.SubElement(new_founisseur,"nom_fournisseur").text=nom
                etree.SubElement(new_founisseur, "adresse").text = adresse
                etree.SubElement(new_founisseur, "télèphone").text = telephone
                etree.SubElement(new_founisseur, "email").text = email
                etree.SubElement(new_founisseur, "date").text = get_date_now()
                #on ajoute dans l'arbre xml
                root_fourisseur.append(new_founisseur)
                #on save dans la base de donner
                tree_fournisseur.write("data/dataFournisseur.xml", encoding="utf-8", pretty_print=True, xml_declaration=True)
                #on afficher dans le tableau
                tab.insert("","end",value=(
                    nom,
                    adresse,
                    telephone,
                    email,
                    get_date_now()
                ))
                # on met ajoute les combobox associe
                nom_fournisseur.append(nom)
                #on effectue les mise à jours
                update_combobox(_w1.Combobox_fournisseur_produit,nom_fournisseur)
                update_combobox(_w1.Combobox_fournisseur_produit_modifier,_w1.Combobox_fournisseur_produit['values'])
                #on vide les champs
                clean_champ_founisseur()
                #on afficher un messager de succe!
                Messagebox.show_info(title="Information",message=f"le fournisseur qui s'appelle {nom} a étè enregistre avec succée!",parent=root)
    elif res=="No":
        #on fait rien
        pass
    else:
        clean_champ_founisseur()
    

