def total_budget():#methode pour avoire la total des produit fois(x) leur prix chacun
    stock_total=[]
    for prod in produits:
        quantite=prod.find('quantite').text
        prix=prod.find('prix').text
        sorties=prod.xpath("mouvement[@type='Sortie']/text()")#on recuperer chaque sortie
        entres=prod.xpath(f"mouvement[@type='Entre']/text()")#on recuparer chaque entre
        stock_actuelle=(int(quantite)+sum(liste_to_int(entres)))-sum(liste_to_int(sorties))#on calcule lestock actuelle
        stock_total.append(stock_actuelle*int(prix))
    return sum(stock_total)


def nombre_stock_critique():#methodes pour avoir le nombre de produit<=25
    compteur=0
    for prod in produits:
        quantite=prod.find('quantite').text
        sorties=prod.xpath("mouvement[@type='Sortie']/text()")#on recuperer chaque sortie
        entres=prod.xpath(f"mouvement[@type='Entre']/text()")#on recuparer chaque entre
        stock_actuelle=(int(quantite)+sum(liste_to_int(entres)))-sum(liste_to_int(sorties))#on calcule les tock actuelle
        if stock_actuelle<=25:
            compteur+=1
        if compteur==0:
            _w1.Label_stockCritique.configure(image=_w1.icone_happy)
        else:
            _w1.Label_stockCritique.configure(image=_w1.icone_sad)
    return str(compteur)


