#methoder pour avoire les elements d'un tableaux
def getTableauItems(tab_target):
    data_=[]
    for items in tab_target.get_children():
        data_=tab_target.item(items,"value")
    return data_


def mois_lettreTO_chiffre(mois):#pour convertir un moi en lettre en chiffre
    dico_mois={
        "Janvier":"01",
        "Février":"02",
         "Mars":"03",
        "Avril":"04",
         "Mai":"05",
        "Juin":"06",
        "Juillet":"07",
        "Août":"08",
         "Septembre":"09",
         "Octobre":"10",
         "Novembre":"11",
        "Décembre":"12"
    }
    return dico_mois[mois]

        

def trimestre_correspondant(T,annee):#pour avoir les date correspondate a chaque trimestre
    #retourer 3 mois et le trimestre correspondate 
    match T:
        case "T1":
            return annee+"-01",annee+"-02",annee+"-03","Trimestre 1 de l'année "+annee
        case "T2":
            return annee+"-04",annee+"-05",annee+"-06","Trimestre 1 de l'année "+annee
        case "T3":
            return annee+"-07",annee+"-08",annee+"-09","Trimestre 1 de l'année "+annee
        case "T4":
            return annee+"-10",annee+"-11",annee+"-12","Trimestre 1 de l'année "+annee


def semestre_correspondant(S,annee):#pour avoir les date correspondate a chaque semestre:
    #retourner 6 mois et le semestre correspondate 
    match S:
        case "S1":
            return annee+"-01",annee+"-02",annee+"-03",annee+"-04",annee+"-05",annee+"-06","Semestre 1 de l'annee "+annee
        case "S2":
            return annee+"-07",annee+"-08",annee+"-09",annee+"-10",annee+"-11",annee+"-12","Semestre 1 de l'annee "+annee


def get_option_rapport():#methode pour avoire les option choisie entre aujourd'hui ou jour specique
    return _w1.choix_rapport.get()


def format_date(date_target,format):#methode pour avoir la date de format jour/mois/annee = 29/09/2025
    date = date_target.strftime(format)
    return date


#pour exportation d'un produit
def exportation(type_=None,categorie=None,table_target=None):
    Messagebox.ok(title="Aider",message="Lors du choix de fichier il faut ajouter son extension si pdf: rapport.pdf si json : rapport.json  si csv: rapport.csv")
    fichier=filedialog.asksaveasfilename(
        title="Choisir un fichier",
        filetypes=[("pdf","*.pdf"),("json","*.json"),("csv","*.csv")]
    )
    if fichier:
        match type_:
            case'rapport':
                data=[["Produit","Stock Initial","Entre","Sortie","Stock Final","Commentaire"]]#titre du tableaux
            case'produit':
                data=[["Produit","Catégorie","Quantite","Prix","Fournisseur","Date(annee-mois-jour)"]]#titre du tableaux
            case'fournisseur':
                data=[["Nom","Adresse","Télèphone","Email","Date"]]#titre du tableaux
        for items in table_target.get_children():
            valeur=table_target.item(items,"value")
            data.append(valeur)
        if fichier.endswith('.pdf'):
            document=SimpleDocTemplate(fichier,pagesize=A4)#creation d'un document pdf
            stylespdf=getSampleStyleSheet()# on recuperer les style qu'on peut faire
            style=stylespdf['Normal']
            # Contenu du PDF
            elements = []
            table_rapport=Table(data)
            # Style du tableau
            table_rapport.setStyle(TableStyle([
                # --- Bordures extérieures et intérieures ---
                ('GRID', (0,0), (-1,-1), 1, colors.black),
                ('BOX', (0,0), (-1,-1), 2, colors.black),

                # --- En-tête ---
                ('BACKGROUND', (0,0), (-1,0), colors.HexColor("#0d6efd")),  # Couleur "primary" Bootstrap
                ('TEXTCOLOR', (0,0), (-1,0), colors.white),
                ('ALIGN', (0,0), (-1,0), 'CENTER'),

                # --- Corps du tableau ---
                ('ALIGN', (0,1), (-1,-1), 'CENTER'),
                ('VALIGN', (0,0), (-1,-1), 'MIDDLE'),
                ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),

                # --- Couleur alternée pour les lignes ---
                ('BACKGROUND', (0,1), (-1,-1), colors.whitesmoke),
                ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.whitesmoke, colors.lightgrey]),

                # --- Espacement ---
                ('TOPPADDING', (0,0), (-1,-1), 6),
                ('BOTTOMPADDING', (0,0), (-1,-1), 6),
            ]))

            if type_=="produit":
                #on teste l'option
                match categorie:
                    case "Tous":
                        titre=Paragraph("Tous les produits:",style)
                    case "Électronique":
                        titre=Paragraph("Tous les produits de catégorie életronique",style)
                    case "Fourniture":
                        titre=Paragraph("Tous les produits de catégorie fourniture",style)
                    case "PPN":
                        titre=Paragraph("Tous les produits de catégorie PPN",style)
                    case "Textille":
                        titre=Paragraph("Tous les produits de catégorie textille",style)
                    case "Accésoire":
                        titre=Paragraph("Tous les produits de catégorie accésoire",style)
                    case "Boisson":
                        titre=Paragraph("Tous les produits de catégorie boisson",style)
                    case None:
                        titre=Paragraph("",style)
            elif type_=="fournisseur":
                 titre=Paragraph("Tous les founisseurs:",style)
            elif type_=="rapport":
                 #on teste l'option
                match option_rapport:
                    case "jour_now":
                        titre=Paragraph(f"Rapport: du {date_target}, Catégorie produit: {_w1.Combobox_categorie_filtre_rapport.get()}",style)
                    case "jour_specifique":
                        titre=Paragraph(f"Rapport: du {date_target}, Catégorie produit: {_w1.Combobox_categorie_filtre_rapport.get()}",style)
                    case "mois_specifique":
                        titre=Paragraph(f"Rapport: du {date_target}, Catégorie produit: {_w1.Combobox_categorie_filtre_rapport.get()}",style)
                    case "annee_specifique":
                        titre=Paragraph(f"Rapport: de l'annee {date_target}, Catégorie produit: {_w1.Combobox_categorie_filtre_rapport.get()}",style)
                    case "trim_specifique":
                        titre=Paragraph(f"Rapport:  {date_target}, Catégorie produit: {_w1.Combobox_categorie_filtre_rapport.get()}",style)
                    case "semestre_specifique":
                        titre=Paragraph(f"Rapport:  {date_target}, Catégorie produit: {_w1.Combobox_categorie_filtre_rapport.get()}",style)
            espace=Spacer(height=10,width=10)
            elements.append(titre)
            elements.append(espace)
            elements.append(table_rapport)
            document.build(elements)
            Messagebox.show_info(title="Information",message=f"Le fichier: '{fichier}'  à étè exporte avec succée !")
        elif fichier.endswith('.json'):
            with open(fichier,'w',encoding="utf-8") as f:
                json.dump(data,f,indent=4)
                Messagebox.show_info(title="Information",message=f"Le fichier: '{fichier}'  à étè exporte avec succée !")
        elif fichier.endswith('.csv'):
            with open(fichier,'w',newline="",encoding="utf-8") as f:
                ecrire=csv.writer(f)
                ecrire.writerows(data)
                Messagebox.show_info(title="Information",message=f"Le fichier: '{fichier}'  à étè exporte avec succée !")


def set_image_icone(source):#methode pour avoire une icone commme image
    img=Image.open(source).resize((24,24))
    icone=ImageTk.PhotoImage(img)
    return icone


def find_produit_by_name(texte):#recherhcer un produit par son nom
    for prod in produits:
        #produit
        nom=prod.find('nom').text
        categorie=prod.find('catégorie').text
        quantite=prod.find('quantite').text
        prix=prod.find('prix').text
        nom_f=prod.find('fournisseur').text
        sorties=prod.xpath("mouvement[@type='Sortie']/text()")#on recuperer chaque sortie
        entres=prod.xpath(f"mouvement[@type='Entre']/text()")#on recuparer chaque entre
        stock_actuelle=(int(quantite)+sum(liste_to_int(entres)))-sum(liste_to_int(sorties))#on calcule lestock actuelle
        date_ajoute=prod.find('date_ajoute').text
        if texte in nom:
           return [nom,categorie,stock_actuelle,prix,nom_f,date_ajoute]
        

