def total_entre_sortie_today():#pour avoir la total des entre et sortie des produits
    total_e=0
    total_s=0
    for prod in produits:
        sorties=prod.xpath(f"mouvement[@type='Sortie' and @date='{get_date_now()}']/text()")#on recuperer chaque sortie
        entres=prod.xpath(f"mouvement[@type='Entre'and  @date='{get_date_now()}']/text()")#on recuparer chaque entre
        total_e+=sum(liste_to_int(entres))
        total_s+=sum(liste_to_int(sorties))
    return total_e,total_s